import{c as h,S as t,j as a,m as i}from"./chunks/framework.8aa1YH_s.js";const u=JSON.parse('{"title":"Lịch sử & Bảng xếp hạng","description":"","frontmatter":{},"headers":[],"relativePath":"hoc-vien/lich-su-xep-hang.md","filePath":"hoc-vien/lich-su-xep-hang.md","lastUpdated":0}'),l={name:"hoc-vien/lich-su-xep-hang.md"};function g(e,n,o,r,c,s){return t(),a("div",null,[...n[0]||(n[0]=[i('<h1 id="lich-su-bang-xep-hang" tabindex="-1">Lịch sử &amp; Bảng xếp hạng <a class="header-anchor" href="#lich-su-bang-xep-hang" aria-label="Permalink to “Lịch sử &amp; Bảng xếp hạng”">​</a></h1><h2 id="lich-su-thi-cua-ban" tabindex="-1">Lịch sử thi của bạn <a class="header-anchor" href="#lich-su-thi-cua-ban" aria-label="Permalink to “Lịch sử thi của bạn”">​</a></h2><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/luyen-tap/lich-su/:idExam/:idDTHV</code> (cho 1 đề cụ thể) hoặc lịch sử tổng hợp trong hồ sơ.</p><h3 id="truy-cap" tabindex="-1">Truy cập <a class="header-anchor" href="#truy-cap" aria-label="Permalink to “Truy cập”">​</a></h3><ul><li>Vào <strong>Hồ sơ cá nhân</strong> → tab <strong>Lịch sử thi</strong>.</li><li>Hoặc vào <strong>Khóa học của tôi</strong> → mở khóa → tab <strong>Lịch sử</strong>.</li></ul><h3 id="bang-lich-su-hien-thi" tabindex="-1">Bảng lịch sử hiển thị <a class="header-anchor" href="#bang-lich-su-hien-thi" aria-label="Permalink to “Bảng lịch sử hiển thị”">​</a></h3><table tabindex="0"><thead><tr><th>Cột</th><th>Ý nghĩa</th></tr></thead><tbody><tr><td>Tên đề</td><td>Tên đề bạn đã làm</td></tr><tr><td>Loại</td><td>Đề ôn / Đề chuyên đề / Đề HSA / Đề TSA / Đề THPT</td></tr><tr><td>Khóa học</td><td>Khóa chứa đề (nếu có)</td></tr><tr><td>Ngày làm</td><td>Thời gian nộp bài</td></tr><tr><td>Điểm</td><td>Điểm bạn đạt</td></tr><tr><td>Tỷ lệ</td><td>% so với điểm tối đa</td></tr><tr><td>Thời gian dùng</td><td>mm:ss bạn dùng (nếu có giới hạn)</td></tr><tr><td>Trạng thái</td><td>Đã chấm xong / Đang chấm / Đã hủy</td></tr><tr><td>Thao tác</td><td>Xem lại / Làm lại (nếu cho phép)</td></tr></tbody></table><h3 id="bo-loc" tabindex="-1">Bộ lọc <a class="header-anchor" href="#bo-loc" aria-label="Permalink to “Bộ lọc”">​</a></h3><ul><li>Theo loại đề</li><li>Theo khóa</li><li>Theo khoảng thời gian</li><li>Theo mức điểm</li></ul><h3 id="sap-xep" tabindex="-1">Sắp xếp <a class="header-anchor" href="#sap-xep" aria-label="Permalink to “Sắp xếp”">​</a></h3><ul><li>Theo ngày (mới nhất / cũ nhất)</li><li>Theo điểm (cao / thấp)</li></ul><h2 id="bieu-đo-tien-bo" tabindex="-1">Biểu đồ tiến bộ <a class="header-anchor" href="#bieu-đo-tien-bo" aria-label="Permalink to “Biểu đồ tiến bộ”">​</a></h2><p>Tab <strong>Tiến bộ</strong> trong Hồ sơ:</p><h3 id="bieu-đo-điem-theo-thoi-gian" tabindex="-1">Biểu đồ điểm theo thời gian <a class="header-anchor" href="#bieu-đo-điem-theo-thoi-gian" aria-label="Permalink to “Biểu đồ điểm theo thời gian”">​</a></h3><ul><li>Trục X: ngày làm bài.</li><li>Trục Y: điểm hoặc tỷ lệ %.</li><li>Mỗi điểm là một bài thi.</li><li><strong>Đường xu hướng</strong>: bạn đang tiến bộ hay đứng yên?</li></ul><h3 id="tien-đo-theo-chu-đe" tabindex="-1">Tiến độ theo chủ đề <a class="header-anchor" href="#tien-đo-theo-chu-đe" aria-label="Permalink to “Tiến độ theo chủ đề”">​</a></h3><ul><li>Biểu đồ radar / cột: <ul><li>Hàm số: 70% → 85% (tăng)</li><li>Lượng giác: 40% → 50% (tăng nhẹ)</li><li>Hình học: 60% → 55% (giảm - cần ôn lại!)</li></ul></li></ul><h3 id="tong-ket" tabindex="-1">Tổng kết <a class="header-anchor" href="#tong-ket" aria-label="Permalink to “Tổng kết”">​</a></h3><ul><li>Tổng số bài đã làm</li><li>Điểm trung bình</li><li>Điểm cao nhất từng đạt</li><li>Thời gian dùng tổng cộng cho việc học</li></ul><h2 id="bang-xep-hang" tabindex="-1">Bảng xếp hạng <a class="header-anchor" href="#bang-xep-hang" aria-label="Permalink to “Bảng xếp hạng”">​</a></h2><h3 id="bang-xep-hang-đe" tabindex="-1">Bảng xếp hạng đề <a class="header-anchor" href="#bang-xep-hang-đe" aria-label="Permalink to “Bảng xếp hạng đề”">​</a></h3><ul><li>Trên trang xem trước của 1 đề, có <strong>Bảng xếp hạng</strong>.</li><li>Xếp theo <strong>điểm cao nhất</strong> từng người đạt được trên đề đó.</li><li>Bạn thấy thứ hạng của mình.</li></ul><h3 id="bang-xep-hang-khoa-hoc" tabindex="-1">Bảng xếp hạng khóa học <a class="header-anchor" href="#bang-xep-hang-khoa-hoc" aria-label="Permalink to “Bảng xếp hạng khóa học”">​</a></h3><ul><li>Trong khóa → tab <strong>Bảng xếp hạng</strong>.</li><li>Tổng hợp điểm các bài thi trong khóa → xếp hạng học viên trong khóa.</li></ul><h3 id="bang-xep-hang-bo-đe" tabindex="-1">Bảng xếp hạng bộ đề <a class="header-anchor" href="#bang-xep-hang-bo-đe" aria-label="Permalink to “Bảng xếp hạng bộ đề”">​</a></h3><ul><li>Trong <a href="./bo-de-thi">Bộ đề thi</a> → tab Xếp hạng.</li><li>Tính tổng điểm các đề trong bộ.</li></ul><h3 id="bang-xep-hang-toan-cong-đong" tabindex="-1">Bảng xếp hạng toàn cộng đồng <a class="header-anchor" href="#bang-xep-hang-toan-cong-đong" aria-label="Permalink to “Bảng xếp hạng toàn cộng đồng”">​</a></h3><ul><li>Trên trang chủ → mục <strong>&quot;Top học viên xuất sắc&quot;</strong> (tùy hệ thống).</li></ul><h2 id="cau-hinh-hien-thi-rieng-tu" tabindex="-1">Cấu hình hiển thị riêng tư <a class="header-anchor" href="#cau-hinh-hien-thi-rieng-tu" aria-label="Permalink to “Cấu hình hiển thị riêng tư”">​</a></h2><p>Nếu không muốn tên mình lên bảng xếp hạng công khai:</p><ul><li>Vào <strong>Hồ sơ cá nhân</strong> → <strong>Cài đặt riêng tư</strong>.</li><li>Tick &quot;Ẩn tên trên bảng xếp hạng&quot; → bạn hiển thị là &quot;Học viên ẩn danh&quot;.</li></ul><h2 id="phan-tich-xu-huong" tabindex="-1">Phân tích xu hướng <a class="header-anchor" href="#phan-tich-xu-huong" aria-label="Permalink to “Phân tích xu hướng”">​</a></h2><p>Hệ thống có thể tự sinh các nhận xét:</p><ul><li>&quot;Trong 4 tuần qua, bạn cải thiện 15% điểm Toán.&quot;</li><li>&quot;Bạn làm tốt phần Đại số nhưng cần ôn thêm Hình học.&quot;</li><li>&quot;Đây là lần thi thử HSA thứ 6 - điểm trung bình của bạn cao hơn 75% học viên cùng đợt.&quot;</li></ul><h2 id="xuat-bao-cao" tabindex="-1">Xuất báo cáo <a class="header-anchor" href="#xuat-bao-cao" aria-label="Permalink to “Xuất báo cáo”">​</a></h2><ul><li>Bấm <strong>Xuất PDF báo cáo cá nhân</strong>.</li><li>File gồm: bảng lịch sử, biểu đồ tiến bộ, phân tích chủ đề, xếp hạng.</li><li>Phù hợp <strong>gửi phụ huynh / giáo viên cá nhân</strong>.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi muốn xóa 1 bài thi tệ khỏi lịch sử?</strong> → Không thể xóa cá nhân (giữ minh bạch). Nhưng có thể đề nghị giáo viên &quot;không tính&quot; nếu có lý do hợp lý.</p><p><strong>Bảng xếp hạng có cập nhật real-time không?</strong> → Cập nhật ngay sau khi bài được chấm xong (vài giây - vài phút).</p><p><strong>Tôi đạt #1 nhưng không thấy tên mình trên bảng xếp hạng công khai?</strong> → Kiểm tra <strong>Cài đặt riêng tư</strong>. Có thể bạn đang ẩn tên.</p><p><strong>Tôi muốn so sánh với 1 bạn cụ thể.</strong> → Hai bạn cùng truy cập bảng xếp hạng của đề/khóa/bộ đề và xem thứ hạng. Một số hệ thống cho phép <strong>kết bạn</strong> để theo dõi tiến bộ của nhau.</p>',41)])])}const b=h(l,[["render",g]]);export{u as __pageData,b as default};
